import { type CardProps, Card as CardRoot, cardVariants } from "./card";
import { CardAction, type CardActionProps } from "./card-action";
import { CardContent, type CardContentProps } from "./card-content";
import { CardDescription, type CardDescriptionProps } from "./card-description";
import { CardFooter, type CardFooterProps } from "./card-footer";
import { CardHeader, type CardHeaderProps } from "./card-header";
import { CardLabel, type CardLabelProps, cardLabelVariants } from "./card-label";
import { CardTitle, type CardTitleProps } from "./card-title";

const Card = Object.assign(CardRoot, {
  Action: CardAction,
  Header: CardHeader,
  Label: CardLabel,
  Title: CardTitle,
  Description: CardDescription,
  Content: CardContent,
  Footer: CardFooter,
});

export { Card, cardVariants, type CardProps };
export { CardAction, type CardActionProps };
export { CardHeader, type CardHeaderProps };
export { CardLabel, cardLabelVariants, type CardLabelProps };
export { CardTitle, type CardTitleProps };
export { CardDescription, type CardDescriptionProps };
export { CardContent, type CardContentProps };
export { CardFooter, type CardFooterProps };

import { cva, type VariantProps } from "class-variance-authority";
import type { ComponentPropsWithRef } from "react";
import { cn } from "@/lib/utils";

export const cardVariants = cva("w-full relative bg-background", {
  variants: {
    surface: {
      flat: "border border-border/50",
      stacked: "border border-border/50 shadow-[3px_3px_0_0_var(--background),4px_4px_0_0_color-mix(in_oklab,var(--border)_50%,transparent)]",
      inset: "shadow-[inset_0_2px_4px_rgba(0,0,0,0.4),inset_0_0_0_1px_color-mix(in_oklab,var(--border)_25%,transparent)] bg-[color-mix(in_oklab,var(--foreground)_3%,var(--background))]",
      dotted: "border border-dashed border-border/70 bg-transparent",
      glow: "border border-border/50 shadow-[0_0_15px_color-mix(in_oklab,var(--border)_12%,transparent),0_0_5px_color-mix(in_oklab,var(--border)_8%,transparent)]",
    },
    size: {
      default: "",
      sm: "max-w-sm",
      md: "max-w-md",
      lg: "max-w-lg",
    },
    interactive: {
      true: "cursor-pointer transition-[border-color,background-color,box-shadow] duration-150 ease-out hover:bg-[color-mix(in_oklab,var(--foreground)_4%,var(--background))] focus-visible:outline-2 focus-visible:outline-ring focus-visible:outline-offset-2",
      false: "",
    },
  },
  compoundVariants: [
    {
      surface: "flat",
      interactive: true,
      className: "hover:border-border",
    },
    {
      surface: "stacked",
      interactive: true,
      className: "hover:shadow-[5px_5px_0_0_var(--background),6px_6px_0_0_color-mix(in_oklab,var(--border)_50%,transparent)]",
    },
    {
      surface: "inset",
      interactive: true,
      className: "hover:shadow-[inset_0_2px_6px_rgba(0,0,0,0.5),inset_0_0_0_1px_color-mix(in_oklab,var(--border)_35%,transparent)]",
    },
    {
      surface: "dotted",
      interactive: true,
      className: "hover:border-border",
    },
    {
      surface: "glow",
      interactive: true,
      className: "hover:border-border/70 hover:shadow-[0_0_20px_color-mix(in_oklab,var(--border)_18%,transparent),0_0_8px_color-mix(in_oklab,var(--border)_12%,transparent)]",
    },
  ],
  defaultVariants: { surface: "flat", size: "default", interactive: false },
});

type CardOwnProps = VariantProps<typeof cardVariants>;
type CardElement = "div" | "article" | "section" | "aside";

export type CardProps<T extends CardElement = "div"> = Omit<
  ComponentPropsWithRef<T>,
  keyof CardOwnProps | "as"
> &
  CardOwnProps & {
    as?: T;
  };

export function Card<T extends CardElement = "div">(props: CardProps<T>) {
  const { as, ref, className, surface, size, interactive, ...rest } =
    props as CardProps<CardElement>;
  const Tag = as ?? "div";
  return (
    <Tag
      data-slot="card"
      data-surface={surface ?? "flat"}
      data-interactive={interactive || undefined}
      // polymorphic ref: the element type is only known at the call site,
      // so the ref type cannot be narrowed inside the generic component body.
      ref={ref as never}
      className={cn(cardVariants({ surface, size, interactive }), className)}
      {...rest}
    />
  );
}

import type { ComponentPropsWithRef } from "react";
import { cn } from "@/lib/utils";

export type CardActionProps = ComponentPropsWithRef<"div">;

export function CardAction({ className, ...props }: CardActionProps) {
  return (
    <div
      data-slot="card-action"
      className={cn("col-start-2 row-span-2 row-start-1 self-start justify-self-end", className)}
      {...props}
    />
  );
}

import type { ComponentPropsWithRef } from "react";
import { cn } from "@/lib/utils";

export type CardHeaderProps = ComponentPropsWithRef<"div">;

export function CardHeader({ className, ...props }: CardHeaderProps) {
  return (
    <div
      data-slot="card-header"
      className={cn(
        "grid auto-rows-min grid-rows-[auto_auto] items-start gap-1.5 border-b border-border px-4 py-3 text-sm text-foreground has-data-[slot=card-action]:grid-cols-[1fr_auto]",
        className,
      )}
      {...props}
    />
  );
}

import type { ComponentPropsWithRef } from "react";
import { cn } from "@/lib/utils";

export type CardTitleProps = ComponentPropsWithRef<"h3"> & {
  as?: "h2" | "h3" | "h4" | "h5";
};

export function CardTitle({ as: Tag = "h3", className, ...props }: CardTitleProps) {
  return <Tag data-slot="card-title" className={cn("text-xl font-bold text-foreground tracking-wide", className)} {...props} />;
}

import type { ComponentPropsWithRef } from "react";
import { cn } from "@/lib/utils";

export type CardDescriptionProps = ComponentPropsWithRef<"p">;

export function CardDescription({ className, ...props }: CardDescriptionProps) {
  return <p data-slot="card-description" className={cn("text-sm text-muted-foreground", className)} {...props} />;
}

import type { ComponentPropsWithRef } from "react";
import { cn } from "@/lib/utils";

export type CardContentProps = ComponentPropsWithRef<"div">;

export function CardContent({ className, ...props }: CardContentProps) {
  return <div data-slot="card-content" className={cn("p-6", className)} {...props} />;
}

import { cva, type VariantProps } from "class-variance-authority";
import type { ComponentPropsWithRef } from "react";
import { cn } from "@/lib/utils";

export const cardLabelVariants = cva(
  "absolute -top-3 left-4 z-[var(--z-base)] bg-background px-2 text-xs font-bold uppercase tracking-wider text-muted-foreground",
  {
    variants: {
      variant: {
        border: "border border-border",
        gap: "",
      },
    },
    defaultVariants: { variant: "border" },
  },
);

export type CardLabelProps = ComponentPropsWithRef<"div"> & VariantProps<typeof cardLabelVariants>;

export function CardLabel({ className, variant, ...props }: CardLabelProps) {
  return <div data-slot="card-label" className={cn(cardLabelVariants({ variant }), className)} {...props} />;
}

import type { ComponentPropsWithRef } from "react";
import { cn } from "@/lib/utils";

export type CardFooterProps = ComponentPropsWithRef<"div">;

export function CardFooter({ className, ...props }: CardFooterProps) {
  return (
    <div data-slot="card-footer" className={cn("flex justify-end gap-3 border-t border-border bg-background/50 px-6 py-4", className)} {...props} />
  );
}
